import json, pathlib, threading
from dataclasses import asdict

PROFILE_DIR = pathlib.Path("memory/profiles")
PROFILE_DIR.mkdir(parents=True, exist_ok=True)

_lock = threading.Lock()

def save_profile(profile: UserProfile) -> None:
    profile.updated_at = datetime.utcnow().isoformat()
    path = PROFILE_DIR / f"{profile.user_id}.json"
    with _lock:
        path.write_text(json.dumps(asdict(profile), indent=2))

def load_profile(user_id: str) -> UserProfile:
    path = PROFILE_DIR / f"{user_id}.json"
    if not path.exists():
        return UserProfile(user_id=user_id)
    data = json.loads(path.read_text())
    return UserProfile(**data)

def update_profile(user_id: str, **kwargs) -> UserProfile:
    """Load, patch, and save a profile atomically."""
    profile = load_profile(user_id)
    for k, v in kwargs.items():
        if hasattr(profile, k):
            setattr(profile, k, v)
    save_profile(profile)
    return profile

import anthropic, re

client = anthropic.Anthropic()

EXTRACT_SYSTEM = """
You observe conversations between a user and an AI assistant.
Extract any user preferences or facts that should update the user profile.
Return ONLY a JSON object with a subset of these keys (omit keys with no new info):
{
  "communication_style": "concise"|"detailed"|"balanced",
  "preferred_format": "prose"|"bullet"|"table",
  "expertise_level": "beginner"|"intermediate"|"expert",
  "domain_focus": ["list", "of", "topics"],
  "tool_preferences": {"key": "value"},
  "name": "string if mentioned",
  "role": "string if mentioned"
}
Return {} if nothing new is observed.
""".strip()

def extract_profile_update(
    user_message: str,
    assistant_reply: str,
) -> dict:
    excerpt = f"User: {user_message}\nAssistant: {assistant_reply}"
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=256,
        system=EXTRACT_SYSTEM,
        messages=[{"role": "user", "content": excerpt}],
    )
    raw = resp.content[0].text.strip()
    m = re.search(r"\{.*\}", raw, re.DOTALL)
    if not m:
        return {}
    try:
        return json.loads(m.group())
    except json.JSONDecodeError:
        return {}

def apply_profile_update(profile: UserProfile, patch: dict) -> UserProfile:
    """Merge a patch dict into the profile, handling list fields carefully."""
    for key, value in patch.items():
        if not hasattr(profile, key):
            continue
        current = getattr(profile, key)
        if isinstance(current, list) and isinstance(value, list):
            # Merge lists, deduplicate, cap at 20 items
            merged = list(dict.fromkeys(current + value))[:20]
            setattr(profile, key, merged)
        elif isinstance(current, dict) and isinstance(value, dict):
            current.update(value)
        else:
            setattr(profile, key, value)
    return profile

@dataclass
class TimestampedPref:
    value: str
    updated_at: str  # ISO timestamp
    source: str      # "explicit" | "learned" | "inferred"

def resolve_pref(prefs: list[TimestampedPref], default: str) -> str:
    """Return the most recent explicit pref, then learned, then inferred."""
    for source_type in ("explicit", "learned", "inferred"):
        candidates = [p for p in prefs if p.source == source_type]
        if candidates:
            # Most recently updated wins within the same source tier
            return max(candidates, key=lambda p: p.updated_at).value
    return default

CURRENT_SCHEMA_VERSION = 2

def migrate_profile_data(data: dict) -> dict:
    """Upgrade serialised profile data to the current schema version."""
    version = data.get("schema_version", 1)

    if version < 2:
        # v1 used a single "style" string; v2 splits into two fields
        old_style = data.pop("style", "balanced")
        data["communication_style"] = old_style
        data["preferred_format"]    = "prose"
        data["schema_version"]      = 2

    # Future versions: add elif version < 3: ... blocks here
    return data

def load_profile(user_id: str) -> UserProfile:
    path = PROFILE_DIR / f"{user_id}.json"
    if not path.exists():
        return UserProfile(user_id=user_id)
    raw  = json.loads(path.read_text())
    data = migrate_profile_data(raw)
    # Drop keys not in dataclass to avoid TypeError on unknown fields
    valid = {k: v for k, v in data.items() if k in UserProfile.__dataclass_fields__}
    return UserProfile(**valid)
